def write(name, text):
    p = PKG / name
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

CONFIG = '# -*- coding: utf-8 -*-\nfrom pathlib import Path\n\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\n\nMETRICS_DIR = STATE_DIR / "metrics"\nMETRICS_SNAPSHOT = METRICS_DIR / "204_metrics_snapshot.json"\nMETRICS_HISTORY = METRICS_DIR / "204_metrics_history.jsonl"\nDASHBOARD_METRICS = METRICS_DIR / "204_dashboard_metrics.json"\n\nTREND_DIR = METRICS_DIR / "trends"\nTREND_FILE = TREND_DIR / "205_metrics_trends.json"\nTREND_HISTORY = TREND_DIR / "205_metrics_trend_history.jsonl"\n'

UTILS = '# -*- coding: utf-8 -*-\nimport json\nimport shutil\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef safe_read(path, limit_chars=5000000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef safe_json(path):\n    path = Path(path)\n    if not path.exists():\n        return None\n    try:\n        return json.loads(safe_read(path))\n    except Exception:\n        return None\n\ndef read_jsonl(path):\n    path = Path(path)\n    rows = []\n    invalid = 0\n    if not path.exists():\n        return rows, invalid\n    for line in safe_read(path).splitlines():\n        if not line.strip():\n            continue\n        try:\n            rows.append(json.loads(line))\n        except Exception:\n            invalid += 1\n    return rows, invalid\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n\ndef append_jsonl(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    with path.open("a", encoding="utf-8") as f:\n        f.write(json.dumps(data, ensure_ascii=False) + "\\n")\n\ndef disk_free_gb(path):\n    usage = shutil.disk_usage(str(path))\n    return round(usage.free / (1024 ** 3), 2)\n'

TREND = '# -*- coding: utf-8 -*-\nfrom config import BASE_DIR, METRICS_SNAPSHOT, METRICS_HISTORY, DASHBOARD_METRICS\nfrom utils import safe_json, read_jsonl, disk_free_gb\n\ndef get_nested(d, path, default=None):\n    cur = d\n    for key in path:\n        if not isinstance(cur, dict):\n            return default\n        cur = cur.get(key)\n        if cur is None:\n            return default\n    return cur\n\ndef normalize_snapshot(row):\n    metrics = row.get("metrics", {})\n    result = row.get("result", {})\n    return {\n        "created_at": row.get("created_at"),\n        "score": result.get("score"),\n        "decision": result.get("decision"),\n        "db_count": get_nested(metrics, ["db", "count"], 0),\n        "queue_total": get_nested(metrics, ["queue", "total"], 0),\n        "queue_finished": get_nested(metrics, ["queue", "finished"], 0),\n        "queue_failed": get_nested(metrics, ["queue", "failed"], 0),\n        "queue_completion_rate": get_nested(metrics, ["queue", "completion_rate"], 0),\n        "workers_total": get_nested(metrics, ["workers", "total"], 0),\n        "workers_idle": get_nested(metrics, ["workers", "idle"], 0),\n        "event_total": get_nested(metrics, ["events", "total"], 0),\n        "event_invalid": get_nested(metrics, ["events", "invalid"], 0),\n        "log_total": get_nested(metrics, ["logs", "total"], 0),\n        "log_invalid": get_nested(metrics, ["logs", "invalid"], 0),\n        "disk_free_gb": get_nested(metrics, ["disk", "free_gb"], None),\n    }\n\ndef delta(first, last, key):\n    try:\n        return (last.get(key) or 0) - (first.get(key) or 0)\n    except Exception:\n        return None\n\ndef build_trends():\n    rows, invalid = read_jsonl(METRICS_HISTORY)\n    latest_snapshot = safe_json(METRICS_SNAPSHOT)\n    dashboard = safe_json(DASHBOARD_METRICS)\n\n    normalized = [normalize_snapshot(x) for x in rows if isinstance(x, dict)]\n    if not normalized and latest_snapshot:\n        normalized = [normalize_snapshot(latest_snapshot)]\n\n    first = normalized[0] if normalized else {}\n    last = normalized[-1] if normalized else {}\n\n    trends = {\n        "source": {\n            "history_file": str(METRICS_HISTORY),\n            "history_rows": len(rows),\n            "history_invalid": invalid,\n            "has_latest_snapshot": latest_snapshot is not None,\n            "has_dashboard_metrics": dashboard is not None,\n        },\n        "current": last,\n        "growth": {\n            "db_delta": delta(first, last, "db_count") if len(normalized) >= 2 else 0,\n            "event_delta": delta(first, last, "event_total") if len(normalized) >= 2 else 0,\n            "log_delta": delta(first, last, "log_total") if len(normalized) >= 2 else 0,\n            "queue_finished_delta": delta(first, last, "queue_finished") if len(normalized) >= 2 else 0,\n        },\n        "quality": {\n            "avg_score": round(sum((x.get("score") or 0) for x in normalized) / len(normalized), 2) if normalized else 0,\n            "latest_score": last.get("score"),\n            "latest_decision": last.get("decision"),\n            "event_invalid_latest": last.get("event_invalid"),\n            "log_invalid_latest": last.get("log_invalid"),\n            "queue_failed_latest": last.get("queue_failed"),\n        },\n        "series": normalized[-100:],\n        "system": {\n            "disk_free_gb_now": disk_free_gb(BASE_DIR),\n        }\n    }\n    return trends\n'

EVALUATOR = '# -*- coding: utf-8 -*-\ndef evaluate(trends):\n    score = 100\n    errors = []\n    warnings = []\n\n    source = trends.get("source", {})\n    quality = trends.get("quality", {})\n    current = trends.get("current", {})\n\n    if not source.get("has_latest_snapshot"):\n        score -= 25\n        errors.append("204 metrics snapshot bulunamadı.")\n\n    if source.get("history_rows", 0) == 0:\n        score -= 10\n        warnings.append("Metrics history boş; trend hesapları sınırlı.")\n\n    if source.get("history_invalid", 0) > 0:\n        score -= min(25, source.get("history_invalid") * 5)\n        warnings.append("Metrics history içinde bozuk satır var.")\n\n    if not current.get("db_count"):\n        score -= 20\n        errors.append("Güncel DB count okunamadı.")\n\n    if quality.get("event_invalid_latest", 0):\n        score -= 10\n        warnings.append("Güncel event invalid satırı var.")\n\n    if quality.get("log_invalid_latest", 0):\n        score -= 10\n        warnings.append("Güncel log invalid satırı var.")\n\n    if quality.get("queue_failed_latest", 0):\n        score -= 10\n        warnings.append("Güncel queue failed job var.")\n\n    score = max(0, min(100, score))\n    decision = "TRENDS BLOCKED" if errors else ("TRENDS READY" if score >= 90 else "TRENDS REVIEW")\n    return {"score": score, "decision": decision, "errors": errors, "warnings": warnings}\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom config import STATE_DIR, REPORT_DIR, TREND_DIR, TREND_FILE, TREND_HISTORY\nfrom utils import now_stamp, now_text, ensure_dirs, write_json, append_jsonl\nfrom trend import build_trends\nfrom evaluator import evaluate\n\ndef run():\n    ensure_dirs(STATE_DIR, REPORT_DIR, TREND_DIR)\n    ts = now_stamp()\n    trends = build_trends()\n    result = evaluate(trends)\n\n    payload = {\n        "module": "205 Metrics History & Trend Engine",\n        "created_at": now_text(),\n        "trends": trends,\n        "result": result,\n    }\n\n    state = STATE_DIR / f"205_metrics_trends_state_{ts}.json"\n    report = REPORT_DIR / f"205_metrics_trends_raporu_{ts}.txt"\n\n    write_json(TREND_FILE, payload)\n    write_json(state, payload)\n    append_jsonl(TREND_HISTORY, payload)\n\n    current = trends.get("current", {})\n    growth = trends.get("growth", {})\n    quality = trends.get("quality", {})\n    source = trends.get("source", {})\n\n    lines = [\n        "="*80,\n        "205 METRICS HISTORY & TREND ENGINE",\n        "="*80,\n        f"Score              : {result[\'score\']} / 100",\n        f"Decision           : {result[\'decision\']}",\n        f"Errors             : {len(result[\'errors\'])}",\n        f"Warnings           : {len(result[\'warnings\'])}",\n        "",\n        "SOURCE",\n        "-"*80,\n        f"History Rows       : {source.get(\'history_rows\')}",\n        f"History Invalid    : {source.get(\'history_invalid\')}",\n        f"Has Snapshot       : {source.get(\'has_latest_snapshot\')}",\n        f"Has Dashboard Data : {source.get(\'has_dashboard_metrics\')}",\n        "",\n        "CURRENT",\n        "-"*80,\n        f"DB Count           : {current.get(\'db_count\')}",\n        f"Queue Total        : {current.get(\'queue_total\')}",\n        f"Queue Finished     : {current.get(\'queue_finished\')}",\n        f"Queue Failed       : {current.get(\'queue_failed\')}",\n        f"Completion Rate    : {current.get(\'queue_completion_rate\')}%",\n        f"Workers Total      : {current.get(\'workers_total\')}",\n        f"Event Total        : {current.get(\'event_total\')}",\n        f"Log Total          : {current.get(\'log_total\')}",\n        "",\n        "GROWTH",\n        "-"*80,\n        f"DB Delta           : {growth.get(\'db_delta\')}",\n        f"Event Delta        : {growth.get(\'event_delta\')}",\n        f"Log Delta          : {growth.get(\'log_delta\')}",\n        f"Queue Finished Δ   : {growth.get(\'queue_finished_delta\')}",\n        "",\n        "QUALITY",\n        "-"*80,\n        f"Average Score      : {quality.get(\'avg_score\')}",\n        f"Latest Score       : {quality.get(\'latest_score\')}",\n        f"Latest Decision    : {quality.get(\'latest_decision\')}",\n        "",\n        "ERRORS",\n        "-"*80,\n    ]\n\n    if result["errors"]:\n        for e in result["errors"]:\n            lines.append(f"- {e}")\n    else:\n        lines.append("Errors: 0")\n\n    lines += ["", "WARNINGS", "-"*80]\n    if result["warnings"]:\n        for w in result["warnings"]:\n            lines.append(f"- {w}")\n    else:\n        lines.append("Warnings: 0")\n\n    lines += [\n        "",\n        "Dosyalar:",\n        str(TREND_FILE),\n        str(TREND_HISTORY),\n        str(state),\n        str(report),\n    ]\n\n    report.write_text("\\n".join(lines), encoding="utf-8")\n    return {"payload": payload, "result": result, "paths": {"trend": str(TREND_FILE), "history": str(TREND_HISTORY), "state": str(state), "report": str(report)}}\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--trend", action="store_true")\n    parser.add_argument("--status", action="store_true")\n    args = parser.parse_args()\n\n    res = run()\n    result = res["result"]\n    trends = res["payload"]["trends"]\n    current = trends.get("current", {})\n    growth = trends.get("growth", {})\n\n    print("="*80)\n    print("205 METRICS HISTORY & TREND ENGINE TAMAMLANDI")\n    print("="*80)\n    print(f"Score           : {result[\'score\']} / 100")\n    print(f"Decision        : {result[\'decision\']}")\n    print(f"Errors          : {len(result[\'errors\'])}")\n    print(f"Warnings        : {len(result[\'warnings\'])}")\n    print(f"DB Count        : {current.get(\'db_count\')}")\n    print(f"DB Delta        : {growth.get(\'db_delta\')}")\n    print(f"Event Delta     : {growth.get(\'event_delta\')}")\n    print(f"Log Delta       : {growth.get(\'log_delta\')}")\n    print("")\n    print("Dosyalar:")\n    print(res["paths"]["trend"])\n    print(res["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'

BRIDGE = '# -*- coding: utf-8 -*-\nimport sys\nfrom pathlib import Path\nPACKAGE_DIR = Path(__file__).resolve().parent / "205"\nsys.path.insert(0, str(PACKAGE_DIR))\nfrom manager import main\nif __name__ == "__main__":\n    main()\n'

